import vex
import requests

@vex.hook(guards=["code_execution", "cve_validation"])
def verify_cve_advisory(message, agent, groupchat):
    if 'cve-' in message:
        cve_id = message.split('CVE-')[1].split()[0]
        response = requests.get(f'https://services.nvd.nist.gov/rest/json/cves/2.0?cveId={cve_id}')
        if response.status_code != 200:
            raise vex.Block(f"Unverified CVE-{cve_id} - requires manual validation")
    return message

# AG2 code execution agent with Vex
code_agent = ag2.AssistantAgent(
    name="CodeResponder",
    message_hooks=[verify_cve_advisory]
)

import vex

@vex.hook(guards=["human_approval", "critical_action"])
def require_human_approval(message, agent, groupchat):
    critical_commands = ['shutdown', 'isolate', 'block_ip', 'quarantine']
    for cmd in critical_commands:
        if cmd in message.lower():
            vex.notify_human(
                title="Critical Action Request",
                message=f"{agent.name} requests: {message}",
                context=groupchat.history[-5:]
            )
            raise vex.PendingApproval(f"Awaiting human approval for {cmd}")
    return message

# Apply to AG2 incident response group
incident_group = ag2.GroupChat(
    agents=[triage_agent, code_agent],
    message_hooks=[require_human_approval]
)
